#include <bits/stdc++.h>
using namespace std;
const int maxn=2e3+5;
int n,top,ans,f[maxn][maxn];
string a,b;
int lena,lenb;
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>a>>b;
	lena=a.size();
	lenb=b.size();
	for(int i=1; i<=lena; i++) {
		f[i][0]=i;
	}
	for(int i=1; i<=lenb; i++) {
		f[0][i]=i;
	}
	for(int i=1; i<=lena; i++) {
		for(int j=1; j<=lenb; j++) {
			if(a[i-1]==b[j-1]) {
				f[i][j]=f[i-1][j-1];
			} else {
				f[i][j]=min({f[i-1][j],f[i][j-1],f[i-1][j-1]})+1;
			}
		}
	}
	cout<<f[lena][lenb];
	return 0;
}
